// BRAIN INGEST — condense Drive docs (Google Docs exported to text by the upstream node)
// into CRM kb_universities / kb_scholarships / kb_sources. Idempotent (skips existing by name/topic).
const ENV  = {};
const BASE = (ENV.CRM_BASE || 'https://crm.eduexpressint.com').replace(/\/$/, '');
const CKEY = ENV.CRM_KEY  || 'eduexpress-n8n-2024';
const CH = { 'Content-Type':'application/json', 'x-api-key': CKEY };
const doHttp = (o) => this.helpers.httpRequest(Object.assign({ timeout: 60000 }, o));
async function cget(p)    { return await doHttp({ method:'GET',  url: BASE + '/api/marketing/' + p, headers: CH, json:true }); }
async function cpost(p,b) { return await doHttp({ method:'POST', url: BASE + '/api/marketing/' + p, headers: CH, body: b, json:true }); }
const TODAY = new Date().toISOString().slice(0,10);
const sleep = (ms)=>new Promise(r=>setTimeout(r,ms));

// 1) Build a corpus from the text files handed in by the upstream Google Drive "Download" node.
const items = $input.all();
let corpus = '';
for (let i = 0; i < items.length; i++) {
  try {
    const buf = await this.helpers.getBinaryDataBuffer(i, 'data');
    const name = (items[i].json && (items[i].json.name || items[i].json.title)) || ('doc' + i);
    corpus += '\n\n===== ' + name + ' =====\n' + buf.toString('utf8');
  } catch (e) { /* skip unreadable item */ }
}
corpus = corpus.slice(0, 60000); // cap to keep tokens sane
if (!corpus.trim()) return [{ json: { ok:false, note:'No readable text from Drive. Check the Google Drive nodes return Google Docs exported to text/plain.' } }];

// 2) Ask the model to extract structured rows.
const prompt =
'You are a data extractor for EduExpress (Bangladesh study-abroad). From the REFERENCE TEXT, extract ONLY clearly-stated facts into JSON.\n' +
'Return ONLY: {"universities":[{"name":"","country":"","city":"","programs":"","tuition":"","lang_req":"","notes":""}],' +
'"scholarships":[{"name":"","country":"","type":"University|Self-paid|Study & Work|Pathway","coverage":"","eligibility":"","deadline":"","notes":""}],' +
'"sources":[{"topic":"","source_type":"positioning|reference|voice_example","use_for":"","notes":""}]}\n' +
'Rules: do NOT invent numbers; copy figures exactly; skip anything not clearly stated; keep notes short. No markdown, no commentary.\n\n' +
'REFERENCE TEXT:\n' + corpus;

// 3) LLM call (OpenCode Go first, then your other keys) — paste keys below.
const KEYS = [
  // { key:'PASTE_OPENCODE_GO_KEY', provider:'opencode-go', model:'glm-5.1' },
  // 'AQ.your-gemini-key',
];
if (KEYS.length === 0) throw new Error('Paste at least one model key into the KEYS array in this node.');
function providerFor(k){ if(/^AIza/.test(k))return{provider:'gemini',model:'gemini-2.0-flash'}; if(/^AQ\./.test(k))return{provider:'gemini',model:'gemini-2.0-flash'}; if(/^gsk_/.test(k))return{provider:'groq',model:'llama-3.3-70b-versatile'}; if(/^sk-or-/.test(k))return{provider:'openrouter',model:'meta-llama/llama-3.1-8b-instruct'}; if(/^sk-/.test(k))return{provider:'openai',model:'gpt-4o-mini'}; return{provider:'gemini',model:'gemini-2.0-flash'}; }
const ENTRIES = KEYS.map(e => typeof e==='string' ? Object.assign({key:e,base:null}, providerFor(e)) : Object.assign({base:null}, providerFor(e.key||''), e));
function prio(p){ return p==='opencode-go'?0 : p==='opencode'?1 : 9; }
ENTRIES.sort((a,b)=>prio(a.provider)-prio(b.provider));
async function callGemini(model,key,p){ const j=await doHttp({method:'POST',url:'https://generativelanguage.googleapis.com/v1beta/models/'+model+':generateContent?key='+key,headers:{'Content-Type':'application/json'},body:{contents:[{parts:[{text:p}]}],generationConfig:{temperature:0.2,maxOutputTokens:8192,responseMimeType:'application/json'}},json:true}); const c=j&&j.candidates&&j.candidates[0]; const t=(c&&c.content&&c.content.parts&&c.content.parts.map(x=>x.text||'').join(''))||''; if(!t) throw new Error('empty gemini'); return t; }
async function callOAI(provider,model,key,p,base){ const bases={groq:'https://api.groq.com/openai/v1',openrouter:'https://openrouter.ai/api/v1',openai:'https://api.openai.com/v1',opencode:'https://opencode.ai/zen/v1','opencode-go':'https://opencode.ai/zen/go/v1'}; const b=base||bases[provider]||bases.openai; const j=await doHttp({method:'POST',url:b+'/chat/completions',headers:{'Content-Type':'application/json','Authorization':'Bearer '+key},body:{model,messages:[{role:'user',content:p}],temperature:0.2,max_tokens:8000},json:true}); return (j&&j.choices&&j.choices[0]&&j.choices[0].message&&j.choices[0].message.content)||''; }
let raw=null,used='',errors=[];
for (let idx=0; idx<ENTRIES.length && raw==null; idx++){ const e=ENTRIES[idx];
  try { raw = e.provider==='gemini' ? await callGemini(e.model,e.key,prompt) : await callOAI(e.provider,e.model,e.key,prompt,e.base); used=e.provider+':'+e.model; }
  catch (err){ errors.push(e.provider+' '+(err&&err.message||err)); await sleep(800); } }
if (raw==null) throw new Error('All model keys failed: '+errors.slice(-4).join(' | '));

// 4) Parse JSON object (salvage braces).
function parseObj(t){ let s=String(t).trim().split('```').join(''); if(s.slice(0,4).toLowerCase()==='json')s=s.slice(4); const a=s.indexOf('{'),b=s.lastIndexOf('}'); s=(a>=0&&b>a)?s.slice(a,b+1):s; return JSON.parse(s); }
let data; try { data = parseObj(raw); } catch(e){ throw new Error('Parse failed ('+e.message+') model='+used+' head='+String(raw).slice(0,160)); }

// 5) Upsert into CRM (idempotent by name/topic).
async function upsert(path, key, rows, mapFn){
  if(!Array.isArray(rows)||!rows.length) return {added:0,skipped:0};
  let have=new Set(); try{ const ex=await cget(path); have=new Set((ex||[]).map(r=>String(r[key]||'').trim().toLowerCase())); }catch(e){}
  let added=0,skipped=0;
  for(const r of rows){ const id=String(r[key]||'').trim().toLowerCase(); if(!id||have.has(id)){skipped++;continue;}
    try{ await cpost(path, mapFn(r)); have.add(id); added++; }catch(e){} }
  return {added,skipped};
}
const u = await upsert('kb/universities','name', data.universities, r=>({name:r.name,country:r.country||'',city:r.city||'',programs:r.programs||'',intakes:'2026',tuition:r.tuition||'',lang_req:r.lang_req||'',admission_url:'',brochure_url:'',partner:1,notes:r.notes||'',last_verified:TODAY}));
const s = await upsert('kb/scholarships','name', data.scholarships, r=>({name:r.name,country:r.country||'',type:r.type||'',coverage:r.coverage||'',eligibility:r.eligibility||'',deadline:r.deadline||'',source_url:'',status:'active',last_verified:TODAY,notes:r.notes||''}));
const c = await upsert('kb/sources','topic', data.sources, r=>({topic:r.topic,url:'',source_type:r.source_type||'reference',use_for:r.use_for||'',date_added:TODAY,notes:r.notes||''}));

return [{ json: { ok:true, used_model:used, docs_read:items.length, universities:u, scholarships:s, sources:c } }];
